const habit = $input.first().json;

// 1. Ambil waktu sekarang dalam zona waktu WIB (UTC+7)
const nowUTC = new Date();
const nowWIB = new Date(nowUTC.getTime() + 7 * 60 * 60 * 1000);
const currentStr = nowWIB.toISOString().substring(11, 19); // Format "HH:mm:ss"

// 2. Fungsi pembantu untuk mengubah string "HH:mm:ss" menjadi objek Date agar bisa dibandingkan
const parseTimeToDate = (timeStr) => {
    const [hours, minutes, seconds] = timeStr.split(':').map(Number);
    const date = new Date(nowWIB); // Gunakan basis tanggal hari ini
    date.setHours(hours, minutes, seconds, 0);
    return date;
};

// 3. Konversi time_start dan time_end asal dari database ke objek Date
const originStart = parseTimeToDate(habit.time_start);
const originEnd = parseTimeToDate(habit.time_end);

// 4. Siapkan variabel penampung untuk hasil akhir berbentuk string
let finalStart = habit.time_start;
let finalEnd = habit.time_end;

// 5. Jarak waktu sekarang ke time_end asal (dalam satuan milidetik)
const timeDiffToEnd = originEnd.getTime() - nowWIB.getTime();
const twoHoursInMs = 2 * 60 * 60 * 1000;

// --- LOGIKA PENGKONDISIAN WAKTU ---

if (originEnd < nowWIB) {
    // KONDISI 1 (PERBAIKAN): Jika time_end asal lebih awal daripada sekarang
    // - time_start TETAP mengunci nilai aslinya (misal: 10:00:00)
    // - time_end BERUBAH mengikuti waktu sekarang (misal: 13:00:00)
    finalStart = habit.time_start;
    finalEnd = currentStr;

} else if (nowWIB < originStart) {
    // KONDISI 2: Jika sekarang lebih awal daripada time_start asal
    // - time_start gunakan waktu sekarang
    finalStart = currentStr;

} else if (nowWIB >= originStart && nowWIB <= originEnd) {
    // KONDISI 3: Jika sekarang berada di antara time_start dan time_end asal
    if (timeDiffToEnd < twoHoursInMs) {
        // Jika jarak waktu ke time_end kurang dari 2 jam, set time_start menjadi 2 jam sebelum time_end
        const newStartObj = new Date(originEnd.getTime() - twoHoursInMs);
        finalStart = newStartObj.toISOString().substring(11, 19);
    }
}

// 6. Hitung poin dan status rutinitas
const newPoints = habit.points + 2;
const newStatus = newPoints >= 10 ? 'ROUTINE' : 'SUGGESTION';

return [{
    json: {
        now:new Date(new Date().getTime() + 7 * 60 * 60 * 1000).toISOString().substring(11, 19),
        id: habit.id,
        points: newPoints,
        status: newStatus,
        last_suggested_at: nowWIB.toISOString().replace('T', ' ').substring(0, 19), // Format SQL Datetime WIB
        time_start: finalStart,
        time_end: finalEnd,
        activity_name: habit.activity_name
    }
}];

// Mengambil data dari node sebelumnya
const rawResponse = $('HTTP Request22').first().json; 
const aiContentText = rawResponse.choices[0].message.content;
const matchmakerData = JSON.parse(aiContentText);

// 1. Mengambil waktu UTC saat ini
const now = new Date();

// 2. Paksa konversi ke Zona Waktu WIB (UTC + 7 Jam)
const wibOffset = 7 * 60 * 60 * 1000; 
const nowWIB = new Date(now.getTime() + wibOffset);

// 3. Membuat blok waktu berdasarkan jam WIB
const timeStart = new Date(nowWIB.getUTCFullYear(), nowWIB.getUTCMonth(), nowWIB.getUTCDate(), nowWIB.getUTCHours(), 0, 0);

// Waktu selesai diset ke 2 jam setelahnya
const timeEnd = new Date(timeStart.getTime() + (2 * 60 * 60 * 1000));

// 4. Konversi ke format string (HH:mm:ss) menggunakan metode UTC agar tidak bergeser lagi
const formatTime = (date) => {
    const hours = String(date.getUTCHours()).padStart(2, '0');
    const minutes = String(date.getUTCMinutes()).padStart(2, '0');
    const seconds = String(date.getUTCSeconds()).padStart(2, '0');
    return `${hours}:${minutes}:${seconds}`;
};

return [{
    json: {
        activity_name: matchmakerData.new_habit_name,
        time_start: formatTime(timeStart),
        time_end: formatTime(timeEnd),
        points: 2,
        status: 'SUGGESTION'
    }
}];

