const items = $input.all();

// 1. Jika database kosong (tidak ada status AWAITING sama sekali)
if (items.length === 0 || !items[0].json.id) {
    return [{ json: { is_locked: false, reason: "Tidak ada kunci" } }];
}

const memoryRow = items[0].json;
let expiresAt = null;

// Perbaikan: Deteksi jika metadata berbentuk string JSON (text dari database)
if (memoryRow.metadata) {
    if (typeof memoryRow.metadata === 'string') {
        try {
            const parsedMetadata = JSON.parse(memoryRow.metadata);
            expiresAt = parsedMetadata.expires_at;
        } catch (e) {
            expiresAt = null; // Gagal parse JSON
        }
    } else {
        expiresAt = memoryRow.metadata.expires_at;
    }
}

const now = new Date();

// 2. Jika kunci ditemukan, mari kita cek jamnya!
if (expiresAt && new Date(expiresAt) > now) {
    // Waktu sekarang masih SEBELUM waktu kedaluwarsa -> MASIH VALID
    return [{
        json: {
            content: memoryRow.content,
            is_locked: true,
            memory_id: memoryRow.id,
            expires_at: expiresAt
        }
    }];
} else {
    // Waktu sekarang sudah LEWAT dari kedaluwarsa -> EXPIRED
    return [{
        json: {
            data: expiresAt, // Sekarang nilai ini akan muncul (tidak undefined lagi)
            content: memoryRow.content,
            is_locked: false,
            reason: "Kunci sudah kedaluwarsa (Expired)",
            expired_memory_id: memoryRow.id 
        }
    }];
}
